package bead

import (
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// newAxonStore returns a *Store wired to a fresh AxonBackend rooted at a
// temp dir. Mirrors newTestStore so the existing high-level Backend method
// surface (Create/Get/Update/Claim/Close/...) gets exercised against the
// axon-shaped storage layout instead of the JSONL default.
func newAxonStore(t *testing.T) *Store {
	t.Helper()
	dir := filepath.Join(t.TempDir(), ".ddx")
	s := NewStore(dir)
	s.backend = NewAxonBackend(dir, s.LockWait)
	require.NoError(t, s.Init())
	return s
}

func TestAxonBackend_InitCreatesCollections(t *testing.T) {
	t.Parallel()
	s := newAxonStore(t)
	ax, ok := s.backend.(*AxonBackend)
	require.True(t, ok)

	for _, path := range []string{ax.BeadsFile, ax.EventsFile} {
		_, err := os.Stat(path)
		assert.NoError(t, err, "axon collection file %s should exist after Init", path)
	}
}

func TestAxonBackend_CreateAndGet(t *testing.T) {
	t.Parallel()
	s := newAxonStore(t)

	b := &Bead{Title: "first", Description: "round-trip"}
	require.NoError(t, s.Create(b))
	require.NotEmpty(t, b.ID)

	got, err := s.Get(b.ID)
	require.NoError(t, err)
	assert.Equal(t, "first", got.Title)
	assert.Equal(t, "round-trip", got.Description)
	assert.Equal(t, StatusOpen, got.Status)
}

func TestAxonBackend_UpdateMutatesAndPersists(t *testing.T) {
	t.Parallel()
	s := newAxonStore(t)

	b := &Bead{Title: "to-update"}
	require.NoError(t, s.Create(b))

	require.NoError(t, s.Update(b.ID, func(bb *Bead) {
		bb.Notes = "added by update"
		bb.Priority = 3
	}))

	// Re-read through a fresh Store wired to the same on-disk dir to prove
	// the change survives the in-memory closure.
	s2 := NewStore(s.Dir)
	s2.backend = NewAxonBackend(s.Dir, s.LockWait)
	got, err := s2.Get(b.ID)
	require.NoError(t, err)
	assert.Equal(t, "added by update", got.Notes)
	assert.Equal(t, 3, got.Priority)
}

func TestAxonBackend_ClaimAndUnclaim(t *testing.T) {
	t.Parallel()
	s := newAxonStore(t)

	b := &Bead{Title: "claimable"}
	require.NoError(t, s.Create(b))

	require.NoError(t, s.Claim(b.ID, "alice"))
	got, err := s.Get(b.ID)
	require.NoError(t, err)
	assert.Equal(t, StatusInProgress, got.Status)
	assert.Equal(t, "alice", got.Owner)
	require.NotNil(t, got.Extra)
	assert.NotEmpty(t, got.Extra["claimed-at"])

	// A second claim against an active claim must fail.
	err = s.Claim(b.ID, "bob")
	require.Error(t, err)

	require.NoError(t, s.Unclaim(b.ID))
	got, err = s.Get(b.ID)
	require.NoError(t, err)
	assert.Equal(t, StatusOpen, got.Status)
	assert.Empty(t, got.Owner)
}

func TestAxonBackend_DepAddRemoveAndTree(t *testing.T) {
	t.Parallel()
	s := newAxonStore(t)

	root := &Bead{Title: "root"}
	child := &Bead{Title: "child"}
	require.NoError(t, s.Create(root))
	require.NoError(t, s.Create(child))

	require.NoError(t, s.DepAdd(child.ID, root.ID))
	got, err := s.Get(child.ID)
	require.NoError(t, err)
	require.Len(t, got.Dependencies, 1)
	assert.Equal(t, root.ID, got.Dependencies[0].DependsOnID)

	tree, err := s.DepTree(root.ID)
	require.NoError(t, err)
	assert.Contains(t, tree, root.ID)

	require.NoError(t, s.DepRemove(child.ID, root.ID))
	got, err = s.Get(child.ID)
	require.NoError(t, err)
	assert.Empty(t, got.Dependencies)
}

func TestAxonBackend_AppendEventSplitsIntoEventsCollection(t *testing.T) {
	t.Parallel()
	s := newAxonStore(t)

	b := &Bead{Title: "with-events"}
	require.NoError(t, s.Create(b))

	for i := 0; i < 3; i++ {
		require.NoError(t, s.AppendEvent(b.ID, BeadEvent{
			Kind:    "test",
			Summary: fmt.Sprintf("event-%d", i),
			Body:    fmt.Sprintf("body-%d", i),
			Actor:   "tester",
		}))
	}

	// Events round-trip through ReadAll / Events.
	events, err := s.Events(b.ID)
	require.NoError(t, err)
	require.Len(t, events, 3)
	for i, e := range events {
		assert.Equal(t, fmt.Sprintf("event-%d", i), e.Summary)
	}

	// And the on-disk event collection actually carries the split entries
	// (TD-030 D3): one entity per event, linked back via event_of.
	ax := s.backend.(*AxonBackend)
	data, err := os.ReadFile(ax.EventsFile)
	require.NoError(t, err)
	lines := bytes.Split(bytes.TrimSpace(data), []byte("\n"))
	require.Len(t, lines, 3)
	for _, line := range lines {
		var env axonEventEnvelope
		require.NoError(t, json.Unmarshal(line, &env))
		assert.Equal(t, AxonEventsCollection, env.Collection)
		assert.Equal(t, b.ID, env.EventOf)
	}

	// And the bead row in ddx_beads must NOT carry inline events — events
	// live in their own collection per TD-030 D3.
	beadData, err := os.ReadFile(ax.BeadsFile)
	require.NoError(t, err)
	beadLines := bytes.Split(bytes.TrimSpace(beadData), []byte("\n"))
	require.Len(t, beadLines, 1)
	var env axonEntityEnvelope
	require.NoError(t, json.Unmarshal(beadLines[0], &env))
	assert.NotContains(t, string(env.Data), `"events"`,
		"bead row in ddx_beads must not carry inline events array")
}

func TestAxonBackend_ListReadyBlocked(t *testing.T) {
	t.Parallel()
	s := newAxonStore(t)

	a := &Bead{Title: "a"}
	b := &Bead{Title: "b"}
	c := &Bead{Title: "c"}
	require.NoError(t, s.Create(a))
	require.NoError(t, s.Create(b))
	require.NoError(t, s.Create(c))
	// b depends on a; c depends on a closed-bead-to-be.
	require.NoError(t, s.DepAdd(b.ID, a.ID))

	all, err := s.List("", "", nil)
	require.NoError(t, err)
	assert.Len(t, all, 3)

	ready, err := s.Ready()
	require.NoError(t, err)
	readyIDs := beadIDSet(ready)
	assert.Contains(t, readyIDs, a.ID, "a has no deps")
	assert.Contains(t, readyIDs, c.ID, "c has no deps")
	assert.NotContains(t, readyIDs, b.ID, "b depends on open a")

	blocked, err := s.Blocked()
	require.NoError(t, err)
	blockedIDs := beadIDSet(blocked)
	assert.Contains(t, blockedIDs, b.ID)
}

func TestAxonBackend_CloseAndArchivePolicy(t *testing.T) {
	t.Parallel()
	s := newAxonStore(t)

	b := &Bead{Title: "to-close"}
	require.NoError(t, s.Create(b))
	require.NoError(t, s.AppendEvent(b.ID, BeadEvent{Kind: "before-close", Summary: "x"}))
	require.NoError(t, s.Close(b.ID))

	got, err := s.Get(b.ID)
	require.NoError(t, err)
	assert.Equal(t, StatusClosed, got.Status, "closed beads stay in ddx_beads (TD-030 archive policy)")

	// Per TD-030 §"Archive policy under axon", closed beads remain in the
	// same ddx_beads collection; the events stay accessible via Events()
	// (the Store externalises them to the attachment sidecar on close).
	events, err := s.Events(b.ID)
	require.NoError(t, err)
	assert.Len(t, events, 1)
}

// TestAxonBackend_JSONLImportExportRoundTrip verifies the bd/br interchange
// contract: a bead exported through the axon-backed store and re-imported
// re-creates the same bead corpus. This is the AC §"JSONL export/import for
// bd/br round-trip" knot.
func TestAxonBackend_JSONLImportExportRoundTrip(t *testing.T) {
	t.Parallel()
	src := newAxonStore(t)

	// Seed a small corpus with deps + events.
	a := &Bead{Title: "alpha"}
	bb := &Bead{Title: "beta"}
	require.NoError(t, src.Create(a))
	require.NoError(t, src.Create(bb))
	require.NoError(t, src.DepAdd(bb.ID, a.ID))
	require.NoError(t, src.AppendEvent(a.ID, BeadEvent{Kind: "k", Summary: "s"}))

	var buf bytes.Buffer
	require.NoError(t, src.ExportTo(&buf))
	require.NotZero(t, buf.Len())

	// Write the export to a temp file and import into a fresh axon-backed
	// store. The expected count should equal the source corpus.
	jsonlPath := filepath.Join(t.TempDir(), "exported.jsonl")
	require.NoError(t, os.WriteFile(jsonlPath, buf.Bytes(), 0o644))

	dst := newAxonStore(t)
	count, err := dst.Import("jsonl", jsonlPath)
	require.NoError(t, err)
	assert.Equal(t, 2, count)

package bead

import (
	"fmt"
	"math/rand"
	"strings"
	"sync"
	"testing"
	"unicode"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// newTestBackend returns a Backend rooted at a fresh temp dir. It exists so
// the chaos suite exercises the JSONL backend through the Backend interface
// (per ddx-bbdd7564 AC §5) rather than through *Store directly.
func newTestBackend(t *testing.T) Backend {
	t.Helper()
	return newTestStore(t)
}

// chaosBackend names a backend constructor for the parameterized chaos suite.
// Per ddx-743bc194, every backend-agnostic chaos scenario must run against both
// the JSONL default and the axon backend so a regression in either path fails
// the same suite.
type chaosBackend struct {
	name string
	make func(*testing.T) Backend
}

func chaosBackends() []chaosBackend {
	return []chaosBackend{
		{name: "jsonl", make: func(t *testing.T) Backend { return newTestStore(t) }},
		{name: "axon", make: func(t *testing.T) Backend { return newAxonStore(t) }},
	}
}

// forEachChaosBackend runs fn once per backend as a parallel subtest. The
// subtest receives a fresh Backend, so scenarios stay isolated per backend.
func forEachChaosBackend(t *testing.T, fn func(*testing.T, Backend)) {
	t.Helper()
	for _, bf := range chaosBackends() {
		bf := bf
		t.Run(bf.name, func(t *testing.T) {
			t.Parallel()
			fn(t, bf.make(t))
		})
	}
}

// TestChaos_ConcurrentAppendSafety spawns 10 goroutines each creating 10 beads
// against the same store. Verifies all 100 beads exist, no duplicates, no corruption.
func TestChaos_ConcurrentAppendSafety(t *testing.T) {
	forEachChaosBackend(t, func(t *testing.T, s Backend) {
		const goroutines = 10
		const beadsEach = 10
		const total = goroutines * beadsEach

		var wg sync.WaitGroup
		errCh := make(chan error, total)

		for g := 0; g < goroutines; g++ {
			g := g
			wg.Add(1)
			go func() {
				defer wg.Done()
				for i := 0; i < beadsEach; i++ {
					b := &Bead{Title: fmt.Sprintf("goroutine-%d-bead-%d", g, i)}
					if err := s.Create(b); err != nil {
						errCh <- fmt.Errorf("goroutine %d create %d: %w", g, i, err)
					}
				}
			}()
		}

		wg.Wait()
		close(errCh)

		var errs []error
		for err := range errCh {
			errs = append(errs, err)
		}
		require.Empty(t, errs, "concurrent creates must not error: %v", errs)

		beads, err := s.ReadAll()
		require.NoError(t, err)
		assert.Len(t, beads, total, "all %d beads must be present", total)

		// Check for duplicates
		seen := make(map[string]int)
		for _, b := range beads {
			seen[b.ID]++
		}
		for id, count := range seen {
			assert.Equal(t, 1, count, "bead %s appears %d times (duplicate)", id, count)
		}

		// Check no corruption: every bead must have a valid ID, title, and status
		for _, b := range beads {
			assert.NotEmpty(t, b.ID, "bead ID must not be empty")
			assert.NotEmpty(t, b.Title, "bead title must not be empty")
			assert.Contains(t, []string{StatusOpen, StatusInProgress, StatusClosed}, b.Status,
				"bead %s has invalid status %q", b.ID, b.Status)
		}
	})
}

// TestChaos_AtomicStatusTransitions spawns 5 goroutines each cycling a single
// bead through open→in_progress→closed→open. After all iterations the bead
// must have a valid status and the store must be fully parseable.
func TestChaos_AtomicStatusTransitions(t *testing.T) {
	forEachChaosBackend(t, func(t *testing.T, s Backend) {
		b := &Bead{Title: "status-churn"}
		require.NoError(t, s.Create(b))
		id := b.ID

		const goroutines = 5
		const iterations = 20

		statuses := []string{StatusOpen, StatusInProgress, StatusClosed}
		var wg sync.WaitGroup

		for g := 0; g < goroutines; g++ {
			g := g
			wg.Add(1)
			go func() {
				defer wg.Done()
				for i := 0; i < iterations; i++ {
					next := statuses[(g+i)%len(statuses)]
					// Ignore errors: contention may cause transient failures that are
					// acceptable (e.g. attempting to set a status that is already set).
					// The critical invariant is no corruption.
					_ = s.Update(id, func(bead *Bead) {
						bead.Status = next
					})
				}
			}()
		}

		wg.Wait()

		// Bead must still exist with a valid status
		got, err := s.Get(id)
		require.NoError(t, err, "bead must be readable after concurrent status updates")
		assert.Contains(t, []string{StatusOpen, StatusInProgress, StatusClosed}, got.Status,
			"bead must have a valid status after concurrent updates")

		// Store must be parseable end-to-end
		allBeads, err := s.ReadAll()
		require.NoError(t, err, "store must be parseable after concurrent status transitions")
		assert.NotEmpty(t, allBeads, "store must not be empty after updates")

		// Verify no partial writes: every entry must decode cleanly
		for _, bead := range allBeads {
			assert.NotEmpty(t, bead.ID)
			assert.NotEmpty(t, bead.Title)
		}
	})
}

// TestChaos_ConcurrentCloseAndAppend reproduces the reported bug:
// one goroutine closes a bead while another creates a new bead concurrently.
// Both operations must persist; neither must clobber the other.
func TestChaos_ConcurrentCloseAndAppend(t *testing.T) {
	forEachChaosBackend(t, func(t *testing.T, s Backend) {
		// Pre-create the bead that will be closed
		existing := &Bead{Title: "to-be-closed"}
		require.NoError(t, s.Create(existing))
		closeID := existing.ID

		const rounds = 50

		for round := 0; round < rounds; round++ {
			// Re-open the bead so we can close it again
			require.NoError(t, s.Update(closeID, func(b *Bead) {
				b.Status = StatusOpen
			}))

			newTitle := fmt.Sprintf("new-bead-round-%d", round)
			var newID string

			var wg sync.WaitGroup
			wg.Add(2)

			// Goroutine A: close the existing bead
			go func() {
				defer wg.Done()
				_ = s.Close(closeID)
			}()

			// Goroutine B: create a new bead
			go func() {
				defer wg.Done()
				nb := &Bead{Title: newTitle}
				if err := s.Create(nb); err == nil {
					newID = nb.ID
				}
			}()

			wg.Wait()

			// The new bead must exist
			if newID != "" {
				got, err := s.Get(newID)
				require.NoError(t, err, "round %d: new bead %s must exist", round, newID)
				assert.Equal(t, newTitle, got.Title, "round %d: new bead title must match", round)
			}

			// The closed bead's status must reflect the close (it may have been
			// re-opened by a subsequent round, but within this round, if the close
			// completed first and create ran after, the close must be visible).
			// The critical check: the closed bead must still exist and be parseable.
			closedBead, err := s.Get(closeID)
			require.NoError(t, err, "round %d: closed bead must still exist", round)
			assert.NotEmpty(t, closedBead.ID, "round %d: closed bead ID must not be empty", round)
		}
	})
}

