// Package bead implements the on-disk bead tracker.
//
// Size envelope (ddx-f8a11202):
//
// Individual bead fields — description, acceptance, notes, and each event's
// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
// through `bd import`. Writers exceeding the cap are truncated with a
// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
// preserve the full payload (notably reviewer streams) should persist to a
// sidecar artifact under `.ddx/executions/<id>/` and record a path
// reference in the event body.
//
// On the read side, scanners use a 16MB buffer — real-world incidents have
// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
// matches the scanner in the agent package.
package bead

import (
	"bufio"
	"bytes"
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
)

// Store manages beads via a pluggable backend.
type Store struct {
	Collection string
	Dir        string
	File       string
	Prefix     string
	LockDir    string
	LockWait   time.Duration
	backend    RawBackend // nil means use built-in JSONL
}

// Compile-time check: *Store satisfies the high-level Backend interface
// declared in backend.go. This is the contract chaos_test.go and (eventually)
// cli/cmd callers program against.
var _ Backend = (*Store)(nil)

type StoreOption func(*Store)

// WithCollection selects the logical bead collection. The default collection
// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
func WithCollection(name string) StoreOption {
	return func(s *Store) {
		if cleaned := normalizeCollection(name); cleaned != "" {
			s.Collection = cleaned
		}
	}
}

// NewStore creates a store with the given directory.
// Defaults can be overridden via options or environment.
func NewStore(dir string, opts ...StoreOption) *Store {
	if dir == "" {
		dir = envOr("DDX_BEAD_DIR", ".ddx")
	}
	workingDir := dir
	if filepath.Base(dir) == ".ddx" {
		workingDir = filepath.Dir(dir)
	}
	prefix := envOr("DDX_BEAD_PREFIX", "")
	var configBackend string
	if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil {
		if prefix == "" && cfg.Bead.IDPrefix != "" {
			prefix = cfg.Bead.IDPrefix
		}
		configBackend = cfg.Bead.Backend
	}
	if prefix == "" {
		prefix = detectPrefix(workingDir)
	}
	// Backend selection: env var wins, then config, then jsonl default.
	backendType := os.Getenv("DDX_BEAD_BACKEND")
	if backendType == "" {
		backendType = configBackend
	}
	if backendType == "" {
		backendType = BackendJSONL
	}

	s := &Store{
		Collection: DefaultCollection,
		Dir:        dir,
		Prefix:     prefix,
		LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
	}
	for _, opt := range opts {
		if opt != nil {
			opt(s)
		}
	}
	spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
	s.File, s.LockDir = spec.PathsUnder(dir)

	// Set up external backend if configured. bd/br lack per-collection
	// scoping in their CLI, so non-default collections (e.g. beads-archive)
	// route through a JSONL fallback the external backend transparently
	// delegates to. The default collection always goes straight to bd/br
	// to preserve the existing interchange contract (schema_compat_test.go,
	// import/export round-trip).
	switch backendType {
	case BackendBD, BackendBR:
		var fallback RawBackend
		if s.Collection != DefaultCollection {
			fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
		}
		if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
			s.backend = ext
		}
		// Fall through to JSONL if tool not available
	case BackendAxon:
		// Per ddx-95ec5ed5 AC §3 the axon backend ships behind a feature
		// flag until ddx-743bc194 (chaos conformance) signs off. Routing
		// only happens when DDX_AXON_EXPERIMENTAL is truthy; otherwise we
		// warn once and fall through to JSONL so the workspace stays
		// usable on misconfiguration.
		if AxonExperimentalEnabled() {
			s.backend = NewAxonBackend(s.Dir, s.LockWait)
		} else {
			fmt.Fprintf(os.Stderr, "bead: backend=axon ignored: set %s=1 to opt in (axon backend is experimental)\n", AxonExperimentalEnv)
		}
	}

	return s
}

// NewStoreWithCollection creates a store for a named logical collection.
func NewStoreWithCollection(dir, collection string) *Store {
	return NewStore(dir, WithCollection(collection))
}

// Init creates the storage directory and file.
func (s *Store) Init() error {
	if s.backend != nil {
		return s.backend.Init()
	}
	if err := os.MkdirAll(s.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: init dir: %w", err)
	}
	f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return fmt.Errorf("bead: init file: %w", err)
	}
	return f.Close()
}

// GenID generates a unique bead ID with the configured prefix.
func (s *Store) GenID() (string, error) {
	b := make([]byte, 4)
	if _, err := rand.Read(b); err != nil {
		return "", fmt.Errorf("bead: gen id: %w", err)
	}
	return fmt.Sprintf("%s-%s", s.Prefix, hex.EncodeToString(b)), nil
}

// ReadAll loads all beads from the configured backend.
func (s *Store) ReadAll() ([]Bead, error) {
	return s.ReadAllFiltered(nil)
}

// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
// those for which the predicate returns true. When the predicate is nil every
// bead is returned (equivalent to ReadAll). The predicate is applied at the
// per-entry parse boundary after fold — matched beads are appended directly to
// the return slice without first being held in an intermediate full-corpus
// list, so queries that match a small subset avoid materializing the
// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
func (s *Store) ReadAllFiltered(pred func(Bead) bool) ([]Bead, error) {
	if s.backend != nil {
		all, err := s.backend.ReadAll()
		if err != nil {
			return nil, err
		}
		if pred == nil {
			return all, nil
		}
		out := make([]Bead, 0, len(all))
		for _, b := range all {
			if pred(b) {
				out = append(out, b)
			}
		}
		return out, nil
	}
	beads, warnings, err := s.readAllRaw()
	if err != nil {
		return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
	}
	beads = foldLatestBeads(beads)
	for _, warning := range warnings {
		fmt.Fprintln(os.Stderr, warning)
	}
	if len(warnings) > 0 && len(beads) > 0 {
		repaired, repairErr := s.repairJSONL()
		if repairErr != nil {
			return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
		}
		if repaired {
			fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
		}
	}
	if len(beads) == 0 && len(warnings) > 0 {
		return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
	}
	if pred == nil {
		return beads, nil
	}
	out := make([]Bead, 0, len(beads))
	for _, b := range beads {
		if pred(b) {
			out = append(out, b)
		}
	}
	return out, nil
}

func (s *Store) readAllRaw() ([]Bead, []string, error) {
	data, err := os.ReadFile(s.File)
	if os.IsNotExist(err) {
		return nil, nil, nil
	}
	if err != nil {
		return nil, nil, fmt.Errorf("read: %w", err)
	}

package axon

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/gorilla/websocket"
)

const graphqlWSSubprotocol = "graphql-transport-ws"

const changeEventsSubscription = `subscription ChangeEvents($projectID: ID!) { changeEvents(projectID: $projectID) { ...ChangeEventFields } }`

// ChangeEvent mirrors the GraphQL subscription payload for lifecycle updates.
type ChangeEvent struct {
	EventID   string    `json:"eventID"`
	BeadID    string    `json:"beadID"`
	Kind      string    `json:"kind"`
	Summary   string    `json:"summary"`
	Body      string    `json:"body"`
	Actor     string    `json:"actor"`
	Timestamp time.Time `json:"timestamp"`
}

// ChangeEventFromLifecycle converts the local bead lifecycle event into the
// Axon GraphQL subscription shape.
func ChangeEventFromLifecycle(src bead.LifecycleEvent) ChangeEvent {
	return ChangeEvent{
		EventID:   src.EventID,
		BeadID:    src.BeadID,
		Kind:      src.Kind,
		Summary:   src.Summary,
		Body:      src.Body,
		Actor:     src.Actor,
		Timestamp: src.Timestamp,
	}
}

// ToLifecycleEvent converts the GraphQL subscription payload back into the
// local bead lifecycle model.
func (c ChangeEvent) ToLifecycleEvent() bead.LifecycleEvent {
	return bead.LifecycleEvent{
		EventID:   c.EventID,
		BeadID:    c.BeadID,
		Kind:      c.Kind,
		Summary:   c.Summary,
		Body:      c.Body,
		Actor:     c.Actor,
		Timestamp: c.Timestamp,
	}
}

// SubscriptionTransport is the minimal GraphQL-over-WebSocket transport used
// by the Axon client subscription path.
type SubscriptionTransport interface {
	Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error)
}

// DualTransport lets callers combine a query transport and a subscription
// transport behind the same Client value.
type DualTransport struct {
	Queries       Transport
	Subscriptions SubscriptionTransport
}

// Query forwards GraphQL queries and mutations to the query transport.
func (d DualTransport) Query(ctx context.Context, query string, variables map[string]any, response any) error {
	if d.Queries == nil {
		return fmt.Errorf("axon: query transport not configured")
	}
	return d.Queries.Query(ctx, query, variables, response)
}

// Subscribe forwards GraphQL subscriptions to the subscription transport.
func (d DualTransport) Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error) {
	if d.Subscriptions == nil {
		return nil, fmt.Errorf("axon: subscription transport not configured")
	}
	return d.Subscriptions.Subscribe(ctx, query, variables)
}

// WebSocketSubscriptionTransport speaks the graphql-transport-ws protocol.
type WebSocketSubscriptionTransport struct {
	URL         string
	Header      http.Header
	Dialer      *websocket.Dialer
	InitPayload map[string]any
}

// NewWebSocketSubscriptionTransport creates a websocket subscription transport
// rooted at url. The URL may be ws://, wss://, http://, or https://.
func NewWebSocketSubscriptionTransport(url string) *WebSocketSubscriptionTransport {
	return &WebSocketSubscriptionTransport{URL: url}
}

// Query is unsupported on the websocket subscription transport.
func (t *WebSocketSubscriptionTransport) Query(context.Context, string, map[string]any, any) error {
	return fmt.Errorf("axon: websocket subscription transport does not execute queries")
}

// Subscribe opens a GraphQL WebSocket subscription and streams raw payloads
// from graphql-transport-ws next messages.
func (t *WebSocketSubscriptionTransport) Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error) {
	url := normalizeWebSocketURL(strings.TrimSpace(t.URL))
	if url == "" {
		return nil, fmt.Errorf("axon: websocket subscription url is required")
	}

	dialer := websocket.DefaultDialer
	if t.Dialer != nil {
		dialer = t.Dialer
	}
	if len(dialer.Subprotocols) == 0 {
		dialer = cloneDialer(dialer)
		dialer.Subprotocols = []string{graphqlWSSubprotocol}
	}

	header := cloneHeader(t.Header)
	conn, _, err := dialer.DialContext(ctx, url, header)
	if err != nil {
		return nil, fmt.Errorf("axon: websocket dial: %w", err)
	}

	closed := make(chan struct{})
	var closeOnce sync.Once
	cleanup := func() {
		closeOnce.Do(func() {
			close(closed)
			_ = conn.Close()
		})
	}
	go func() {
		select {
		case <-ctx.Done():
			cleanup()
		case <-closed:
		}
	}()

	if conn.Subprotocol() != "" && conn.Subprotocol() != graphqlWSSubprotocol {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subprotocol mismatch: got %q want %q", conn.Subprotocol(), graphqlWSSubprotocol)
	}

	if err := conn.WriteJSON(graphqlWSMessage{Type: "connection_init", Payload: mustJSON(t.InitPayload)}); err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket connection_init: %w", err)
	}

	for {
		var msg graphqlWSMessage
		if err := conn.ReadJSON(&msg); err != nil {
			cleanup()
			return nil, fmt.Errorf("axon: websocket ack: %w", err)
		}
		switch msg.Type {
		case "connection_ack":
			goto subscribed
		case "ping":
			_ = conn.WriteJSON(graphqlWSMessage{Type: "pong"})
		case "error":
			cleanup()
			return nil, fmt.Errorf("axon: websocket connection error")
		}
	}

subscribed:
	subPayload, err := json.Marshal(map[string]any{
		"query":     query,
		"variables": variables,
	})
	if err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subscribe payload: %w", err)
	}
	if err := conn.WriteJSON(graphqlWSMessage{ID: "1", Type: "subscribe", Payload: subPayload}); err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subscribe: %w", err)
	}

	out := make(chan json.RawMessage)
	go func() {
		defer close(out)
		defer cleanup()
		for {
			var msg graphqlWSMessage
			if err := conn.ReadJSON(&msg); err != nil {
				return
			}
			switch msg.Type {
			case "next":
				if len(msg.Payload) == 0 {
					continue
				}
				payload := append(json.RawMessage(nil), msg.Payload...)
				select {
				case out <- payload:
				case <-ctx.Done():
					return
				}
			case "complete":
				return
			case "ping":
				_ = conn.WriteJSON(graphqlWSMessage{Type: "pong"})
			case "error":
				return
			}
		}
	}()

	return out, nil
}

type graphqlWSMessage struct {
	ID      string          `json:"id,omitempty"`
	Type    string          `json:"type"`
	Payload json.RawMessage `json:"payload,omitempty"`
}

type changeEventsEnvelope struct {
	Data struct {
		ChangeEvents *ChangeEvent `json:"changeEvents,omitempty"`
	} `json:"data"`
}

func normalizeWebSocketURL(url string) string {
	switch {
	case strings.HasPrefix(url, "http://"):
		return "ws://" + strings.TrimPrefix(url, "http://")
	case strings.HasPrefix(url, "https://"):
		return "wss://" + strings.TrimPrefix(url, "https://")
	default:
		return url
	}

